using System;
using System.Linq;
using Avalonia.Controls;
using Avalonia.Data;
using Avalonia.UnitTests;

static int Check(string name, Control target, Action setInvalid, Action setValid)
{
    Console.WriteLine($"Checking {name}...");

    var failures = 0;
    if (DataValidationErrors.GetHasErrors(target) || DataValidationErrors.GetErrors(target) is not null)
    {
        Console.WriteLine("  FAIL: control unexpectedly starts with validation errors.");
        failures++;
    }

    setInvalid();
    var invalidHasErrors = DataValidationErrors.GetHasErrors(target);
    var invalidErrors = DataValidationErrors.GetErrors(target)?.ToList();
    Console.WriteLine($"  Invalid: HasErrors={invalidHasErrors}, ErrorCount={invalidErrors?.Count ?? 0}");

    if (!invalidHasErrors || invalidErrors?.Count != 1 || invalidErrors[0] is not InvalidOperationException)
    {
        Console.WriteLine("  FAIL: invalid input did not surface the expected validation exception.");
        failures++;
    }

    setValid();
    var validHasErrors = DataValidationErrors.GetHasErrors(target);
    var validErrors = DataValidationErrors.GetErrors(target);
    Console.WriteLine($"  Valid:   HasErrors={validHasErrors}, Errors={(validErrors is null ? "<null>" : string.Join(",", validErrors))}");

    if (validHasErrors || validErrors is not null)
    {
        Console.WriteLine("  FAIL: valid input did not clear validation errors.");
        failures++;
    }

    return failures;
}

using var app = UnitTestApplication.Start();

var textBox = new TextBox
{
    DataContext = new ExceptionTest(),
    [!TextBox.TextProperty] = new Binding(nameof(ExceptionTest.LessThan10)) { Mode = BindingMode.TwoWay },
};

var comboBox = new ComboBox
{
    IsEditable = true,
    DataContext = new ExceptionTest(),
    [!ComboBox.TextProperty] = new Binding(nameof(ExceptionTest.LessThan10)) { Mode = BindingMode.TwoWay },
};

var failures = 0;
failures += Check("TextBox.Text", textBox, () => textBox.Text = "20", () => textBox.Text = "1");
failures += Check("ComboBox.Text", comboBox, () => comboBox.Text = "20", () => comboBox.Text = "1");

if (failures != 0)
{
    Console.WriteLine($"Validation failure(s): {failures}");
    Environment.Exit(1);
}

Console.WriteLine("All validation checks passed.");

sealed class ExceptionTest
{
    private int _lessThan10;

    public int LessThan10
    {
        get => _lessThan10;
        set
        {
            if (value < 10)
                _lessThan10 = value;
            else
                throw new InvalidOperationException("More than 10.");
        }
    }
}
EOF
